patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 24a166906f1f..4d6af23f4fd1 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1229,22 +1229,49 @@ static Instruction *foldAddToAshr(BinaryOperator &Add) {
   // Division must be by power-of-2, but not the minimum signed value.
   Value *X;
   const APInt *DivC;
-  if (!match(Add.getOperand(0), m_SDiv(m_Value(X), m_Power2(DivC))) ||
-      DivC->isNegative())
+  // Match either operand as sdiv and the other as sext.
+  Value *Op0 = Add.getOperand(0), *Op1 = Add.getOperand(1);
+  Value *SDivOp = nullptr;
+  Value *SExtOp = nullptr;
+  if (match(Op0, m_SDiv(m_Value(X), m_Power2(DivC))) && !DivC->isNegative()) {
+    SDivOp = Op0;
+    SExtOp = Op1;
+  } else if (match(Op1, m_SDiv(m_Value(X), m_Power2(DivC))) && !DivC->isNegative()) {
+    SDivOp = Op1;
+    SExtOp = Op0;
+  } else {
     return nullptr;
+  }

   // Rounding is done by adding -1 if the dividend (X) is negative and has any
   // low bits set. The canonical pattern for that is an "ugt" compare with SMIN:
   // sext (icmp ugt (X & (DivC - 1)), SMIN)
+  // Also handle equality pattern for DivC == 2:
+  // sext (icmp eq (X & MaskC), MaskC) where MaskC = SMin | (DivC - 1)
   const APInt *MaskC;
+  const APInt *CompareC;
   ICmpInst::Predicate Pred;
-  if (!match(Add.getOperand(1),
+  if (!match(SExtOp,
              m_SExt(m_ICmp(Pred, m_And(m_Specific(X), m_APInt(MaskC)),
-                           m_SignMask()))) ||
-      Pred != ICmpInst::ICMP_UGT)
+                           m_APInt(CompareC)))))
     return nullptr;

   APInt SMin = APInt::getSignedMinValue(Add.getType()->getScalarSizeInBits());
+  if (Pred == ICmpInst::ICMP_UGT) {
+    if (*CompareC != SMin)
+      return nullptr;
+  } else if (Pred == ICmpInst::ICMP_EQ) {
+    // For equality pattern, the compare constant must be equal to MaskC.
+    if (*CompareC != *MaskC)
+      return nullptr;
+    // Equality pattern is only safe when there is exactly one low bit in the mask,
+    // i.e., DivC == 2, because only then the condition matches negative odd numbers.
+    if ((*DivC - 1).popcount() != 1)
+      return nullptr;
+  } else {
+    return nullptr;
+  }
+
   if (*MaskC != (SMin | (*DivC - 1)))
     return nullptr;

